#!/usr/bin/env python3
"""cfgpipe - Command-line configuration resolver.

Reads a JSON schema document from disk, resolves each declared parameter
from local sources, and writes the resolved configuration to stdout as JSON.
Every resolved leaf value is a string.
"""

import argparse
import json
import os
import sys
import urllib.request
import urllib.error
from typing import Any


class ConfigError(Exception):
    """Exception raised for configuration resolution errors."""
    pass


def parse_cli_args(args: list[str]) -> dict[str, str]:
    """Parse CLI arguments in --name=value or -name=value format.

    Last wins for duplicate names. Only arguments after the schema-file path
    participate.
    """
    result: dict[str, str] = {}
    for arg in args:
        if '=' not in arg:
            continue
        name_part, _, value = arg.partition('=')
        # Strip leading dashes
        if name_part.startswith('--'):
            name = name_part[2:]
        elif name_part.startswith('-'):
            name = name_part[1:]
        else:
            continue
        result[name] = value
    return result


def read_schema(schema_path: str) -> dict[str, dict[str, Any]]:
    """Read and validate the schema file.

    Returns the parsed schema dict.

    Raises ConfigError on file missing, invalid JSON, or validation failure.
    """
    try:
        with open(schema_path, 'r') as f:
            content = f.read()
    except FileNotFoundError:
        raise ConfigError(f"Schema file not found: {schema_path}")
    except OSError as e:
        raise ConfigError(f"Cannot read schema file {schema_path}: {e}")

    try:
        schema = json.loads(content)
    except json.JSONDecodeError as e:
        raise ConfigError(f"Invalid JSON in schema file {schema_path}: {e}")

    if not isinstance(schema, dict):
        raise ConfigError(f"Schema root must be an object, got {type(schema).__name__}")

    # Validate each parameter declaration
    primary_store_keys = {}
    for param_name, param_decl in schema.items():
        if not isinstance(param_decl, dict):
            raise ConfigError(
                f"Parameter '{param_name}' must be an object declaration"
            )
        if 'type' not in param_decl:
            raise ConfigError(
                f"Parameter '{param_name}' is missing required 'type' field"
            )

        # Validate source fields are strings if present
        for field in ('default', 'env', 'file', 'arg'):
            if field in param_decl and not isinstance(param_decl[field], str):
                raise ConfigError(
                    f"Parameter '{param_name}' has non-string '{field}' field"
                )

        # Track primary-store keys for duplicate detection
        if 'primary-store' in param_decl:
            ps_key = param_decl['primary-store']
            if not isinstance(ps_key, str):
                raise ConfigError(
                    f"Parameter '{param_name}' has non-string 'primary-store' field"
                )
            if ps_key in primary_store_keys:
                raise ConfigError(
                    f"Parameters '{primary_store_keys[ps_key]}' and '{param_name}' "
                    f"share the same primary-store key '{ps_key}'"
                )
            primary_store_keys[ps_key] = param_name

    return schema, primary_store_keys


def fetch_primary_store_value(
    base_url: str,
    key: str,
    param_name: str
) -> str | None:
    """Fetch a value from the primary store.

    Returns the value as a string if found, None if not found.
    Raises ConfigError on connector failures or parse errors.
    """
    import urllib.parse
    import urllib.request
    import urllib.error
    import json as json_module

    url = f"{base_url}/v1/primary/kv?key={urllib.parse.quote(key, safe='')}"

    try:
        req = urllib.request.Request(url, method='GET')
        try:
            with urllib.request.urlopen(req, timeout=30) as response:
                if response.status == 200:
                    body = response.read().decode('utf-8')
                    try:
                        data = json_module.loads(body)
                    except json_module.JSONDecodeError as e:
                        raise ConfigError(
                            f"Parameter '{param_name}': primary-store response is not valid JSON: {e}"
                        )

                    if not isinstance(data, dict):
                        raise ConfigError(
                            f"Parameter '{param_name}': primary-store response must be a JSON object"
                        )

                    if 'found' not in data:
                        raise ConfigError(
                            f"Parameter '{param_name}': primary-store response missing 'found' field"
                        )

                    if not data['found']:
                        return None

                    if 'value' not in data:
                        raise ConfigError(
                            f"Parameter '{param_name}': primary-store response for present key missing 'value' field"
                        )

                    value = data['value']
                    if not isinstance(value, str):
                        raise ConfigError(
                            f"Parameter '{param_name}': primary-store 'value' field must be a string"
                        )

                    return value
                else:
                    raise ConfigError(
                        f"Parameter '{param_name}': primary-store returned unexpected status {response.status}"
                    )
        except urllib.error.HTTPError as e:
            # Handle 404 as missing key (per spec: 404 Not Found with body {"found": false} means key missing)
            if e.code == 404:
                # Try to read the response body
                try:
                    body = e.read().decode('utf-8')
                except:
                    body = '""'
                # Check if it's a proper {"found": false} response
                try:
                    data = json_module.loads(body)
                    if isinstance(data, dict) and data.get('found') is False:
                        return None
                except json_module.JSONDecodeError:
                    pass
                return None
            else:
                raise ConfigError(
                    f"Parameter '{param_name}': primary-store HTTP error {e.code}: {e.reason}"
                )
    except urllib.error.URLError as e:
        raise ConfigError(
            f"Parameter '{param_name}': primary-store network error: {e}"
        )


def parse_value(value: str, value_type: str, param_name: str, source: str) -> str:
    """Parse a raw string value against the declared type.

    Returns the value as a string (possibly formatted per type rules).
    Raises ConfigError on parse failure.

    All resolved values are returned as strings.
    """
    value = value.strip()

    if value_type == 'string':
        return value

    elif value_type == 'integer':
        try:
            # Must be a decimal integer, no scientific notation
            int(value)
            # Verify no scientific notation was accepted (int() would handle it)
            # Check for scientific notation indicators
            if 'e' in value.lower() or 'E' in value:
                raise ConfigError(
                    f"Parameter '{param_name}' cannot parse source '{source}': "
                    f"scientific notation not allowed for integer"
                )
            return value
        except ValueError:
            raise ConfigError(
                f"Parameter '{param_name}': cannot parse source '{source}' "
                f"'{value}' as integer"
            )

    elif value_type == 'float':
        try:
            # Must be a decimal input, no scientific notation required
            if 'e' in value.lower() or 'E' in value:
                raise ConfigError(
                    f"Parameter '{param_name}' cannot parse source '{source}': "
                    f"scientific notation not allowed for float"
                )
            float(value)
            return value
        except ValueError:
            raise ConfigError(
                f"Parameter '{param_name}': cannot parse source '{source}' "
                f"'{value}' as float"
            )

    elif value_type == 'boolean':
        lower_value = value.lower()
        if lower_value in ('true', 'false'):
            return lower_value
        raise ConfigError(
            f"Parameter '{param_name}': cannot parse source '{source}' "
            f"'{value}' as boolean (expected 'true' or 'false')"
        )

    else:
        raise ConfigError(
            f"Parameter '{param_name}': unknown type '{value_type}'"
        )


def resolve_parameter(
    param_name: str,
    param_decl: dict[str, Any],
    cli_args: dict[str, str],
    primary_store_url: str | None = None
) -> str | None:
    """Resolve a single parameter from its declared sources.

    Priority order (highest to lowest): arg > primary-store > file > env > default.
    Returns the resolved value as a string, or None if unresolved.
    Raises ConfigError on parse failure.
    """
    value_type = param_decl['type']

    # 1. Check CLI argument (highest priority)
    if 'arg' in param_decl:
        arg_name = param_decl['arg']
        if arg_name in cli_args:
            raw_value = cli_args[arg_name]
            return parse_value(raw_value, value_type, param_name, 'arg')

    # 2. Check primary store (second highest priority)
    if primary_store_url is not None and 'primary-store' in param_decl:
        ps_key = param_decl['primary-store']
        raw_value = fetch_primary_store_value(primary_store_url, ps_key, param_name)
        if raw_value is not None:
            return parse_value(raw_value, value_type, param_name, 'primary-store')

    # 3. Check file
    if 'file' in param_decl:
        file_path = param_decl['file']
        try:
            with open(file_path, 'r') as f:
                raw_value = f.read()
        except (FileNotFoundError, OSError):
            raw_value = None

        if raw_value is not None:
            raw_value = raw_value.strip()
            if raw_value != '':
                return parse_value(raw_value, value_type, param_name, 'file')

    # 4. Check environment variable
    if 'env' in param_decl:
        env_name = param_decl['env']
        try:
            raw_value = os.environ[env_name]
        except KeyError:
            raw_value = None

        if raw_value is not None and raw_value.strip() != '':
            return parse_value(raw_value, value_type, param_name, 'env')

    # 5. Check default (lowest priority)
    if 'default' in param_decl:
        raw_value = param_decl['default']
        return parse_value(raw_value, value_type, param_name, 'default')

    # No source provided a value
    return None


def main() -> int:
    """Main entry point.

    Returns exit code (0 for success, non-zero for failure).
    """
    parser = argparse.ArgumentParser(
        prog='cfgpipe',
        description='Configuration resolver',
        add_help=False
    )
    parser.add_argument('--primary-store', help='Primary store base URL')
    parser.add_argument('schema_file', help='Path to JSON schema file')
    parser.add_argument('arg_candidates', nargs='*', help='CLI argument candidates')

    # Parse known args to get schema file and primary-store, keep rest for CLI arg parsing
    args, remaining = parser.parse_known_args()

    # Read and validate schema
    try:
        schema, primary_store_keys = read_schema(args.schema_file)
    except ConfigError as e:
        print(f"Error: {e}", file=sys.stderr)
        return 1

    # Validate primary-store configuration
    if primary_store_keys:
        if args.primary_store is None:
            # At least one parameter declares primary-store but flag is absent
            params_with_ps = list(primary_store_keys.values())
            if len(params_with_ps) == 1:
                print(f"Error: Parameter '{params_with_ps[0]}' declares 'primary-store' but no --primary-store flag provided", file=sys.stderr)
            else:
                params_str = "', '".join(params_with_ps)
                print(f"Error: Parameters '{params_str}' declare 'primary-store' but no --primary-store flag provided", file=sys.stderr)
            return 1

    # Parse CLI arguments from remaining (including arg_candidates)
    all_cli_args = args.arg_candidates + remaining
    cli_args = parse_cli_args(all_cli_args)

    # Resolve each parameter
    resolved: dict[str, str] = {}
    unresolved: list[str] = []

    for param_name in sorted(schema.keys()):  # Process in consistent order
        param_decl = schema[param_name]
        try:
            value = resolve_parameter(param_name, param_decl, cli_args, args.primary_store)
            if value is None:
                unresolved.append(param_name)
            else:
                resolved[param_name] = value
        except ConfigError as e:
            print(f"Error: {e}", file=sys.stderr)
            return 1

    # Check for unresolved parameters
    if unresolved:
        if len(unresolved) == 1:
            print(f"Error: Parameter '{unresolved[0]}' is unresolved", file=sys.stderr)
        else:
            params_str = "', '".join(unresolved)
            print(f"Error: Parameters '{params_str}' are unresolved", file=sys.stderr)
        return 1

    # Write resolved configuration to stdout
    output = json.dumps(resolved, sort_keys=False)
    print(output)
    return 0


if __name__ == '__main__':
    sys.exit(main())

"""cfgpipe - Configuration pipeline core implementation."""

import os
import json
from typing import Any
from .types import TypeRegistry


class SchemaError(Exception):
    """Raised when schema validation fails."""

    def __init__(self, message: str, path: str | None = None, details: dict[str, Any] | None = None):
        super().__init__(message)
        self.path = path
        self.details = details or {}


class ResolutionError(Exception):
    """Raised when parameter resolution fails."""

    def __init__(self, message: str, path: str, source: str, detail: str):
        super().__init__(message)
        self.path = path
        self.source = source
        self.detail = detail


class _Parameter:
    """Internal representation of a parameter declaration."""

    __slots__ = ['type', 'default', 'env', 'file', 'arg', 'primary_store']

    def __init__(
        self,
        type: str,
        default: str | None = None,
        env: str | None = None,
        file: str | None = None,
        arg: str | None = None,
        primary_store: str | None = None
    ):
        self.type = type
        self.default = default
        self.env = env
        self.file = file
        self.arg = arg
        self.primary_store = primary_store


class _SchemaValidator:
    """Validates schema structure and collects parameter declarations."""

    SOURCE_KEYS = {'default', 'env', 'file', 'arg', 'primary-store'}

    def __init__(self, registry: TypeRegistry):
        self.registry = registry
        self.errors: list[SchemaError] = []

    def validate(self, schema: dict[str, Any]) -> dict[str, _Parameter]:
        """Validate schema and return parameter declarations keyed by path."""
        if not isinstance(schema, dict):
            raise SchemaError("schema root must be an object")
        if not schema:
            raise SchemaError("schema root must be non-empty")

        params: dict[str, _Parameter] = {}
        primary_stores: dict[str, str] = {}  # primary-store key -> path

        self._validate_group(schema, '', params, primary_stores)

        if self.errors:
            raise self.errors[0]

        return params

    def _validate_group(
        self,
        group: dict[str, Any],
        path: str,
        params: dict[str, _Parameter],
        primary_stores: dict[str, str]
    ) -> None:
        """Recursively validate a group and its contents."""
        if not isinstance(group, dict):
            self.errors.append(SchemaError(
                f"group at '{path}' must be an object",
                path if path else None
            ))
            return

        # Check if group has type field - that's invalid
        if 'type' in group:
            self.errors.append(SchemaError(
                f"group '{path}' must not define a 'type' field for itself",
                path if path else None
            ))
            return

        # Check for source annotations on group
        for key in self.SOURCE_KEYS:
            if key in group:
                val = group[key]
                if isinstance(val, str):
                    self.errors.append(SchemaError(
                        f"group '{path}' must not contain source-annotation '{key}' with non-object value",
                        path if path else None
                    ))
                    return

        for name, value in group.items():
            if not isinstance(name, str):
                self.errors.append(SchemaError(
                    f"schema key must be a string, got {type(name).__name__}",
                    path if path else None
                ))
                continue

            # Build the full path for this entry
            entry_path = f"{path}.{name}" if path else name

            # Must be object-valued
            if not isinstance(value, dict):
                self.errors.append(SchemaError(
                    f"entry '{entry_path}' must be object-valued",
                    entry_path
                ))
                continue

            # Check if this is a parameter (has type field)
            if 'type' in value:
                self._validate_parameter(value, entry_path, params, primary_stores)
            else:
                # This is a nested group
                self._validate_group(value, entry_path, params, primary_stores)

    def _validate_parameter(
        self,
        param: dict[str, Any],
        path: str,
        params: dict[str, _Parameter],
        primary_stores: dict[str, str]
    ) -> None:
        """Validate a parameter declaration."""
        # Check type field
        if 'type' not in param or not isinstance(param['type'], str):
            self.errors.append(SchemaError(
                f"parameter '{path}' must have a string-valued 'type' field",
                path
            ))
            return

        type_name = param['type']

        # Check if type is recognized
        if not self.registry.has(type_name):
            self.errors.append(SchemaError(
                f"parameter '{path}' has unrecognized type '{type_name}'",
                path
            ))
            return

        # Validate source keys
        default = param.get('default')
        env = param.get('env')
        file = param.get('file')
        arg = param.get('arg')
        primary_store = param.get('primary-store')

        # Validate types of source values
        for key, val in [('default', default), ('env', env), ('file', file), ('arg', arg), ('primary-store', primary_store)]:
            if val is not None and not isinstance(val, str):
                self.errors.append(SchemaError(
                    f"parameter '{path}' source-annotation '{key}' must have a string value",
                    path
                ))
                return

        # Check duplicate primary-store
        if primary_store is not None:
            if primary_store in primary_stores:
                self.errors.append(SchemaError(
                    f"duplicate primary-store key '{primary_store}' used by '{primary_stores[primary_store]}' and '{path}'",
                    path
                ))
                return
            primary_stores[primary_store] = path

        # Store parameter
        params[path] = _Parameter(
            type=type_name,
            default=default,
            env=env,
            file=file,
            arg=arg,
            primary_store=primary_store
        )


class _SourceResolver:
    """Resolves parameter values from various sources."""

    def __init__(self, registry: TypeRegistry):
        self.registry = registry

    def resolve(
        self,
        params: dict[str, _Parameter],
        cli_args: dict[str, str] | None = None,
        env: dict[str, str] | None = None,
        file_contents: dict[str, str] | None = None
    ) -> dict[str, str]:
        """Resolve all parameters and return the configuration dict with string values."""
        result: dict[str, str] = {}
        errors: list[tuple[str, str, str]] = []  # (path, source, detail)

        for path, param in params.items():
            type_obj = self.registry.get(param.type)
            if type_obj is None:
                errors.append((path, 'schema', f"type '{param.type}' not found"))
                continue

            value, source = self._resolve_parameter(param, cli_args, env, file_contents)

            if value is not None:
                try:
                    # Validate the value
                    type_obj.parse(value, path)
                    # Use raw string value
                    result[path] = value
                except ValueError as e:
                    errors.append((path, source, str(e)))
            elif param.default is not None:
                try:
                    # Validate the default value
                    type_obj.parse(param.default, path)
                    # Use raw string value
                    result[path] = param.default
                except ValueError as e:
                    errors.append((path, 'default', str(e)))

        if errors:
            # Raise first error
            path, source, detail = errors[0]
            raise ResolutionError(
                f"failed to resolve parameter '{path}' from {source}",
                path=path,
                source=source,
                detail=detail
            )

        return result

    def _resolve_parameter(
        self,
        param: _Parameter,
        cli_args: dict[str, str] | None,
        env: dict[str, str] | None,
        file_contents: dict[str, str] | None
    ) -> tuple[str | None, str | None]:
        """Resolve a single parameter value, return (value, source) or (None, None)."""
        # Priority: arg > env > file > default
        if param.arg and cli_args is not None and param.arg in cli_args:
            return (cli_args[param.arg], 'arg')
        if param.env and env is not None and param.env in env:
            return (env[param.env], 'env')
        if param.file and file_contents is not None and param.file in file_contents:
            return (file_contents[param.file].strip(), 'file')
        return (None, None)


def _build_output(params: dict[str, _Parameter], resolved: dict[str, str], schema: dict[str, Any]) -> dict[str, Any]:
    """Build nested output dict from resolved parameters, preserving group structure."""
    # First, build the full structure from schema
    def copy_structure(schema_node: dict[str, Any]) -> dict[str, Any]:
        """Copy the schema structure without values."""
        node = {}
        for key, value in schema_node.items():
            if 'type' in value:
                # This is a leaf parameter
                continue
            else:
                # This is a group
                node[key] = copy_structure(value)
        return node

    result = copy_structure(schema)

    # Fill in resolved values
    for path, value in resolved.items():
        parts = path.split('.')
        current = result
        for part in parts[:-1]:
            if part not in current:
                # Create intermediate structure
                current[part] = {}
            current = current[part]
        current[parts[-1]] = value

    return result


class Config:
    """Configuration manager with hierarchical schema and type resolution."""

    def __init__(self, schema: dict[str, Any], registry: TypeRegistry | None = None):
        """Initialize with a schema.

        Args:
            schema: The configuration schema as a nested dict
            registry: Optional custom type registry (defaults to global)
        """
        from .types import BuiltinTypes
        self.registry = registry or TypeRegistry()
        self.schema = self._validate_schema(schema)
        self.params = self._collect_parameters(schema)

    def _validate_schema(self, schema: dict[str, Any]) -> dict[str, Any]:
        """Validate the schema structure."""
        validator = _SchemaValidator(self.registry)
        return schema  # Return validated schema

    def _collect_parameters(self, schema: dict[str, Any]) -> dict[str, _Parameter]:
        """Collect parameter declarations from schema."""
        validator = _SchemaValidator(self.registry)
        return validator.validate(schema)

    def resolve(
        self,
        cli_args: dict[str, str] | None = None,
        env: dict[str, str] | None = None,
        file_contents: dict[str, str] | None = None
    ) -> dict[str, Any]:
        """Resolve configuration from various sources.

        Args:
            cli_args: Command-line arguments as dict
            env: Environment variables as dict
            file_contents: File contents keyed by filename

        Returns:
            Nested dict with resolved string values, mirroring schema hierarchy
        """
        resolver = _SourceResolver(self.registry)
        resolved = resolver.resolve(self.params, cli_args, env, file_contents)
        return _build_output(self.params, resolved, self.schema)

    def get_parameter_names(self) -> list[str]:
        """Get list of all parameter paths."""
        return list(self.params.keys())

    def get_group_names(self) -> list[str]:
        """Get list of all group paths."""
        groups = set()
        for path in self.params.keys():
            parts = path.split('.')
            for i in range(1, len(parts)):
                groups.add('.'.join(parts[:i]))
        return sorted(groups)


def load_schema_file(path: str) -> dict[str, Any]:
    """Load a schema from a JSON file."""
    with open(path, 'r') as f:
        return json.load(f)


def save_config(config: dict[str, Any], path: str) -> None:
    """Save configuration to a JSON file."""
    with open(path, 'w') as f:
        json.dump(config, f, indent=2)

"""Custom parameter types and type registry."""

from abc import ABC, abstractmethod
from typing import Any
import re


class Type(ABC):
    """Base class for parameter types."""

    @abstractmethod
    def parse(self, value: str, path: str) -> Any:
        """Parse a string value into a typed value. Returns the parsed value.

        Must raise ValueError if the value doesn't match the type.
        """
        pass

    @abstractmethod
    def render(self, value: Any) -> str:
        """Render a typed value back to a string."""
        pass


class StringType(Type):
    """String type - no conversion needed."""

    def parse(self, value: str, path: str) -> str:
        return value

    def render(self, value: Any) -> str:
        return str(value)


class IntegerType(Type):
    """Integer type."""

    def parse(self, value: str, path: str) -> int:
        try:
            return int(value)
        except ValueError:
            raise ValueError(f"invalid integer: {value!r}")

    def render(self, value: Any) -> str:
        return str(int(value))


class FloatType(Type):
    """Float type."""

    def parse(self, value: str, path: str) -> float:
        try:
            return float(value)
        except ValueError:
            raise ValueError(f"invalid float: {value!r}")

    def render(self, value: Any) -> str:
        return str(float(value))


class BooleanType(Type):
    """Boolean type - accepts 'true'/'false', '1'/'0', 'yes'/'no', 'on'/'off' (case insensitive)."""

    TRUE_VALUES = {"true", "1", "yes", "on"}
    FALSE_VALUES = {"false", "0", "no", "off"}

    def parse(self, value: str, path: str) -> bool:
        lower = value.lower()
        if lower in self.TRUE_VALUES:
            return True
        if lower in self.FALSE_VALUES:
            return False
        raise ValueError(f"invalid boolean: {value!r}")

    def render(self, value: Any) -> str:
        return "true" if bool(value) else "false"


class PortType(Type):
    """Port type - integer 0-65535, rendered as plain decimal with no leading zeros except '0'."""

    def parse(self, value: str, path: str) -> int:
        try:
            port = int(value)
        except ValueError:
            raise ValueError(f"invalid port (not an integer): {value!r}")
        if port < 0 or port > 65535:
            raise ValueError(f"port out of range (0-65535): {port}")
        # Check for leading zeros
        if value != "0" and value.startswith("0"):
            raise ValueError(f"port has leading zeros: {value!r}")
        return port

    def render(self, value: Any) -> str:
        return str(int(value))


class TypeRegistry:
    """Registry for parameter types."""

    def __init__(self):
        self._types: dict[str, Type] = {}
        self._register_builtins()

    def _register_builtins(self):
        """Register built-in types."""
        self.register("string", StringType())
        self.register("integer", IntegerType())
        self.register("float", FloatType())
        self.register("boolean", BooleanType())
        self.register("port", PortType())

    def register(self, name: str, type_obj: Type) -> None:
        """Register a custom type."""
        self._types[name] = type_obj

    def get(self, name: str) -> Type | None:
        """Get a type by name."""
        return self._types.get(name)

    def has(self, name: str) -> bool:
        """Check if a type exists."""
        return name in self._types

    def list_types(self) -> list[str]:
        """List all registered type names."""
        return list(self._types.keys())


# Global type registry instance
_builtin_registry = TypeRegistry()


class BuiltinTypes:
    """Access to built-in types."""

    STRING = _builtin_registry.get("string")
    INTEGER = _builtin_registry.get("integer")
    FLOAT = _builtin_registry.get("float")
    BOOLEAN = _builtin_registry.get("boolean")
    PORT = _builtin_registry.get("port")

    @staticmethod
    def register(name: str, type_obj: Type) -> None:
        """Register a type with the global registry."""
        _builtin_registry.register(name, type_obj)

    @staticmethod
    def get(name: str) -> Type | None:
        """Get a type from the global registry."""
        return _builtin_registry.get(name)

    @staticmethod
    def has(name: str) -> bool:
        """Check if a type exists in the global registry."""
        return _builtin_registry.has(name)


def register_type(name: str, type_obj: Type) -> None:
    """Register a custom type."""
    BuiltinTypes.register(name, type_obj)

